SELECT protein_name 
FROM proteins 
WHERE protein_function = 'enzymatic activity';

SELECT variant_id, position 
FROM variants 
WHERE variant_id = 1;

SELECT p.protein_name, p.organism, v.functional_impact, v.pathogenicity
FROM proteins p
LEFT JOIN variants v ON p.protein_id = v.protein_id;

SELECT AVG(score) AS average_glow
FROM variants
WHERE functional_impact = 'loss of function';
